    animal:'Grey Parrot', animalEmoji:'🦜', mastername:'Loro',
    flagColors:['#3E9A00','#FFFFFF','#E32118','#0073CE'],
    intro:"¡Hola! I'm Loro the Grey Parrot! Equatorial Guinea — Africa's only Spanish-speaking nation!",
